const mensagens = $json.message || [];

return mensagens.map((item) => {
  let parsed;
  try {
    parsed = JSON.parse(item);
  } catch (e) {
    parsed = { erro: 'Falha ao parsear', original: item };
  }

  return {
    json: parsed,
  };
});

