// Retorna cada item como um objeto seQparado
return itens
  .map(item => item.trim())
  .filter(item => item !== '')
  .map(item => ({ item }));

const src = $input.first().json;

let texto = src.item ?? src.output ?? src.text ?? src.content ?? '';
texto = String(texto || '').trim();
if (!texto) return [];

// 1) Normaliza quebras de linha
texto = texto
  .replace(/\r\n/g, '\n')
  .replace(/\\\\n/g, '\n')
  .replace(/\\n/g, '\n');

// 2) Configuração
const MAX_CHARS_POR_MENSAGEM = 280;

// 3) Protege abreviações comuns pra não serem tratadas como fim de frase
//    Substitui o ponto por um placeholder temporário
const PLACEHOLDER = '\u0000'; // caractere nulo como placeholder

const abreviacoes = [
  'Dra', 'Dr', 'Sra', 'Sr', 'Prof', 'Profa',
  'Jr', 'Av', 'R', 'Al', 'Pça',
  'ex', 'etc', 'obs', 'tel', 'cel',
  'min', 'seg', 'hrs', 'vol',
  'pg', 'pag', 'fig', 'cap',
  'nº', 'nro', 'qtd', 'aprox'
];

function protegerAbreviacoes(text) {
  let resultado = text;
  for (const abrev of abreviacoes) {
    // Protege "Dra." "Dr." etc. (case insensitive)
    // Só protege quando seguido de espaço + letra (não fim de texto)
    const regex = new RegExp(`\\b(${abrev})\\.\\s(?=[A-Za-zÀ-ú])`, 'gi');
    resultado = resultado.replace(regex, `$1${PLACEHOLDER} `);
  }
  return resultado;
}

function restaurarAbreviacoes(text) {
  return text.replace(new RegExp(PLACEHOLDER, 'g'), '.');
}

// 4) Divide texto em frases
function splitIntoSentences(text) {
  // Protege abreviações
  let protegido = protegerAbreviacoes(text);

  const blocks = protegido.split('\n').map(b => b.trim()).filter(Boolean);
  const sentences = [];

  for (const block of blocks) {
    // Quebra após pontuação real (.!?) seguida de espaço ou fim
    const parts = block.match(/[^.!?]*[.!?]+[\s]?|[^.!?]+$/g);
    if (parts) {
      for (const part of parts) {
        const trimmed = part.trim();
        if (trimmed) {
          // Restaura os pontos das abreviações
          sentences.push(restaurarAbreviacoes(trimmed));
        }
      }
    } else {
      sentences.push(restaurarAbreviacoes(block));
    }
  }

  return sentences;
}

// 5) Agrupa frases em mensagens
function groupSentencesIntoMessages(sentences, maxChars) {
  const messages = [];
  let currentMsg = '';

  for (const sentence of sentences) {
    if (sentence.length > maxChars) {
      if (currentMsg.trim()) {
        messages.push(currentMsg.trim());
        currentMsg = '';
      }
      messages.push(sentence.trim());
      continue;
    }

    const tentativa = currentMsg ? (currentMsg + ' ' + sentence) : sentence;

    if (tentativa.length <= maxChars) {
      currentMsg = tentativa;
    } else {
      if (currentMsg.trim()) {
        messages.push(currentMsg.trim());
      }
      currentMsg = sentence;
    }
  }

  if (currentMsg.trim()) {
    messages.push(currentMsg.trim());
  }

  return messages;
}

// 6) Executa
const frases = splitIntoSentences(texto);
const partes = groupSentencesIntoMessages(frases, MAX_CHARS_POR_MENSAGEM);

return partes.map(p => ({ json: { item: p } }));

// Gera delay entre 25 e 90 segundos
const min = 10;
const max = 30;
const delay = Math.floor(Math.random() * (max - min + 1)) + min;
return [{ json: { ...$input.first().json, wait_seconds: delay } }];
